import { useState, useEffect, useCallback } from "react";
import {
  LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid,
  Tooltip, Legend, ResponsiveContainer, ReferenceLine, Area, AreaChart, ComposedChart
} from "recharts";

const KHULNA_LAT = 22.8098;
const KHULNA_LON = 89.5644;

const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];

function groupByMonth(dates, maxTemp, minTemp, meanTemp, humidity) {
  const monthly = {};
  dates.forEach((d, i) => {
    const [year, month] = d.split("-");
    const key = `${year}-${month}`;
    if (!monthly[key]) monthly[key] = { label: `${MONTHS[parseInt(month)-1]} ${year}`, maxT: [], minT: [], meanT: [], hum: [] };
    if (maxTemp[i] != null) monthly[key].maxT.push(maxTemp[i]);
    if (minTemp[i] != null) monthly[key].minT.push(minTemp[i]);
    if (meanTemp[i] != null) monthly[key].meanT.push(meanTemp[i]);
    if (humidity[i] != null) monthly[key].hum.push(humidity[i]);
  });
  return Object.entries(monthly).map(([k, v]) => ({
    key: k,
    label: v.label,
    maxTemp: avg(v.maxT),
    minTemp: avg(v.minT),
    meanTemp: avg(v.meanT),
    humidity: avg(v.hum),
  }));
}

function avg(arr) {
  if (!arr.length) return null;
  return parseFloat((arr.reduce((a, b) => a + b, 0) / arr.length).toFixed(1));
}

function getDailyData(dates, maxTemp, minTemp, humidity, yearFilter) {
  return dates.reduce((acc, d, i) => {
    const [year] = d.split("-");
    if (yearFilter !== "all" && year !== yearFilter) return acc;
    acc.push({
      date: d,
      label: d.slice(5),
      maxTemp: maxTemp[i],
      minTemp: minTemp[i],
      humidity: humidity[i],
    });
    return acc;
  }, []);
}

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{
      background: "rgba(10,20,35,0.95)", border: "1px solid #1e4d6b",
      borderRadius: 10, padding: "10px 16px", color: "#e0f4ff", fontSize: 13
    }}>
      <div style={{ fontWeight: 700, marginBottom: 6, color: "#7dd3fc" }}>{label}</div>
      {payload.map((p, i) => (
        <div key={i} style={{ color: p.color, marginBottom: 2 }}>
          {p.name}: <b>{p.value != null ? p.value : "—"}{p.unit || ""}</b>
        </div>
      ))}
    </div>
  );
};

export default function KhulnaWeather() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [view, setView] = useState("monthly"); // monthly | daily
  const [yearFilter, setYearFilter] = useState("all");
  const [tab, setTab] = useState("temp"); // temp | humidity | both

  useEffect(() => {
    const fetchData = async () => {
      try {
        const url = `https://archive-api.open-meteo.com/v1/archive?latitude=${KHULNA_LAT}&longitude=${KHULNA_LON}&start_date=2021-01-01&end_date=2024-12-31&daily=temperature_2m_max,temperature_2m_min,temperature_2m_mean,relative_humidity_2m_mean&timezone=Asia%2FDhaka`;
        const res = await fetch(url);
        const json = await res.json();
        setData(json);
      } catch (e) {
        setError("Failed to fetch weather data.");
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const monthly = data ? groupByMonth(
    data.daily.time,
    data.daily.temperature_2m_max,
    data.daily.temperature_2m_min,
    data.daily.temperature_2m_mean,
    data.daily.relative_humidity_2m_mean,
  ) : [];

  const filteredMonthly = yearFilter === "all" ? monthly : monthly.filter(m => m.key.startsWith(yearFilter));

  const daily = data ? getDailyData(
    data.daily.time,
    data.daily.temperature_2m_max,
    data.daily.temperature_2m_min,
    data.daily.relative_humidity_2m_mean,
    yearFilter
  ) : [];

  // Stats
  const allTemps = data ? data.daily.temperature_2m_mean.filter(Boolean) : [];
  const allHum = data ? data.daily.relative_humidity_2m_mean.filter(Boolean) : [];
  const allMax = data ? data.daily.temperature_2m_max.filter(Boolean) : [];

  const statCards = [
    { label: "Avg Temperature", value: allTemps.length ? avg(allTemps) + "°C" : "—", icon: "🌡️", color: "#fb923c" },
    { label: "Avg Humidity", value: allHum.length ? avg(allHum) + "%" : "—", icon: "💧", color: "#38bdf8" },
    { label: "Max Recorded", value: allMax.length ? Math.max(...allMax).toFixed(1) + "°C" : "—", icon: "🔥", color: "#f87171" },
    { label: "Min Humidity", value: allHum.length ? Math.min(...allHum).toFixed(0) + "%" : "—", icon: "🏜️", color: "#a3e635" },
  ];

  const years = ["all", "2021", "2022", "2023", "2024"];
  const chartData = view === "monthly" ? filteredMonthly : daily;

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(160deg, #050e1a 0%, #071a2e 40%, #0a2440 100%)",
      fontFamily: "'Georgia', serif",
      color: "#cce8f8",
      padding: "0 0 40px 0",
    }}>
      {/* Header */}
      <div style={{
        padding: "36px 32px 20px",
        borderBottom: "1px solid #0f3455",
        background: "rgba(0,0,0,0.25)",
        backdropFilter: "blur(8px)",
        position: "sticky", top: 0, zIndex: 10
      }}>
        <div style={{ maxWidth: 960, margin: "0 auto", display: "flex", alignItems: "flex-end", justifyContent: "space-between", flexWrap: "wrap", gap: 16 }}>
          <div>
            <div style={{ fontSize: 11, letterSpacing: 4, color: "#38bdf8", textTransform: "uppercase", marginBottom: 4 }}>Bangladesh · 22.81°N 89.56°E</div>
            <h1 style={{ margin: 0, fontSize: 32, fontWeight: 700, color: "#e0f4ff", letterSpacing: -0.5 }}>
              Khulna Weather Archive
            </h1>
            <div style={{ fontSize: 13, color: "#64a7c8", marginTop: 4 }}>Daily Temperature & Humidity · 2021 – 2024</div>
          </div>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            {years.map(y => (
              <button key={y} onClick={() => setYearFilter(y)} style={{
                padding: "6px 16px", borderRadius: 20, border: "1px solid",
                borderColor: yearFilter === y ? "#38bdf8" : "#1e4d6b",
                background: yearFilter === y ? "#0c3a5e" : "transparent",
                color: yearFilter === y ? "#7dd3fc" : "#4a8aaa",
                cursor: "pointer", fontSize: 13, fontFamily: "inherit", transition: "all 0.2s"
              }}>{y === "all" ? "All Years" : y}</button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 960, margin: "0 auto", padding: "0 24px" }}>
        {/* Stat Cards */}
        {!loading && !error && (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: 16, margin: "28px 0 0" }}>
            {statCards.map((s, i) => (
              <div key={i} style={{
                background: "rgba(255,255,255,0.04)", border: "1px solid #102d4a",
                borderRadius: 14, padding: "20px 22px",
                boxShadow: "0 4px 24px rgba(0,0,0,0.3)"
              }}>
                <div style={{ fontSize: 24, marginBottom: 8 }}>{s.icon}</div>
                <div style={{ fontSize: 26, fontWeight: 700, color: s.color }}>{s.value}</div>
                <div style={{ fontSize: 12, color: "#64a7c8", marginTop: 4, letterSpacing: 0.5 }}>{s.label}</div>
              </div>
            ))}
          </div>
        )}

        {loading && (
          <div style={{ textAlign: "center", padding: "80px 0", color: "#38bdf8" }}>
            <div style={{ fontSize: 48, marginBottom: 16 }}>🌀</div>
            <div style={{ fontSize: 16, letterSpacing: 2 }}>Loading weather archive…</div>
          </div>
        )}

        {error && (
          <div style={{ textAlign: "center", padding: "60px 0", color: "#f87171" }}>
            <div style={{ fontSize: 32 }}>⚠️</div>
            <div style={{ marginTop: 12 }}>{error}</div>
          </div>
        )}

        {!loading && !error && (
          <>
            {/* View + Tab Controls */}
            <div style={{ display: "flex", gap: 12, margin: "28px 0 20px", flexWrap: "wrap", alignItems: "center", justifyContent: "space-between" }}>
              <div style={{ display: "flex", gap: 4, background: "rgba(255,255,255,0.04)", borderRadius: 10, padding: 4, border: "1px solid #0f3455" }}>
                {[["monthly", "Monthly Avg"], ["daily", "Daily View"]].map(([v, l]) => (
                  <button key={v} onClick={() => setView(v)} style={{
                    padding: "7px 18px", borderRadius: 7, border: "none",
                    background: view === v ? "#0c3a5e" : "transparent",
                    color: view === v ? "#7dd3fc" : "#4a8aaa",
                    cursor: "pointer", fontSize: 13, fontFamily: "inherit"
                  }}>{l}</button>
                ))}
              </div>
              <div style={{ display: "flex", gap: 4, background: "rgba(255,255,255,0.04)", borderRadius: 10, padding: 4, border: "1px solid #0f3455" }}>
                {[["temp", "🌡️ Temperature"], ["humidity", "💧 Humidity"], ["both", "⚡ Combined"]].map(([v, l]) => (
                  <button key={v} onClick={() => setTab(v)} style={{
                    padding: "7px 14px", borderRadius: 7, border: "none",
                    background: tab === v ? "#0c3a5e" : "transparent",
                    color: tab === v ? "#7dd3fc" : "#4a8aaa",
                    cursor: "pointer", fontSize: 12, fontFamily: "inherit"
                  }}>{l}</button>
                ))}
              </div>
            </div>

            {/* Temperature Chart */}
            {(tab === "temp" || tab === "both") && (
              <div style={{
                background: "rgba(255,255,255,0.03)", border: "1px solid #102d4a",
                borderRadius: 16, padding: "24px 12px 12px", marginBottom: 20
              }}>
                <div style={{ paddingLeft: 16, marginBottom: 16 }}>
                  <div style={{ fontSize: 13, color: "#38bdf8", letterSpacing: 2, textTransform: "uppercase" }}>Surface Temperature</div>
                  <div style={{ fontSize: 18, fontWeight: 700, color: "#e0f4ff", marginTop: 4 }}>
                    {view === "monthly" ? "Monthly Averages" : `Daily Records — ${yearFilter === "all" ? "All Years" : yearFilter}`}
                  </div>
                </div>
                <ResponsiveContainer width="100%" height={280}>
                  {view === "monthly" ? (
                    <AreaChart data={chartData} margin={{ top: 5, right: 20, left: 0, bottom: 5 }}>
                      <defs>
                        <linearGradient id="maxGrad" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#f97316" stopOpacity={0.3}/>
                          <stop offset="95%" stopColor="#f97316" stopOpacity={0}/>
                        </linearGradient>
                        <linearGradient id="minGrad" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#38bdf8" stopOpacity={0.2}/>
                          <stop offset="95%" stopColor="#38bdf8" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3" />
                      <XAxis dataKey="label" tick={{ fill: "#4a8aaa", fontSize: 11 }} interval={2} />
                      <YAxis tick={{ fill: "#4a8aaa", fontSize: 11 }} unit="°C" domain={[10, 42]} />
                      <Tooltip content={<CustomTooltip />} />
                      <Legend wrapperStyle={{ color: "#7dd3fc", fontSize: 12 }} />
                      <Area type="monotone" dataKey="maxTemp" name="Max Temp" stroke="#f97316" fill="url(#maxGrad)" strokeWidth={2} dot={false} unit="°C" />
                      <Area type="monotone" dataKey="meanTemp" name="Mean Temp" stroke="#facc15" fill="none" strokeWidth={1.5} dot={false} unit="°C" strokeDasharray="4 2" />
                      <Area type="monotone" dataKey="minTemp" name="Min Temp" stroke="#38bdf8" fill="url(#minGrad)" strokeWidth={2} dot={false} unit="°C" />
                    </AreaChart>
                  ) : (
                    <ComposedChart data={chartData} margin={{ top: 5, right: 20, left: 0, bottom: 5 }}>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3" />
                      <XAxis dataKey="label" tick={{ fill: "#4a8aaa", fontSize: 10 }} interval={Math.floor(daily.length / 12)} />
                      <YAxis tick={{ fill: "#4a8aaa", fontSize: 11 }} unit="°C" domain={[10, 45]} />
                      <Tooltip content={<CustomTooltip />} />
                      <Legend wrapperStyle={{ color: "#7dd3fc", fontSize: 12 }} />
                      <Area type="monotone" dataKey="maxTemp" name="Max Temp" stroke="#f97316" fill="#f9731620" strokeWidth={1.5} dot={false} unit="°C" />
                      <Area type="monotone" dataKey="minTemp" name="Min Temp" stroke="#38bdf8" fill="#38bdf820" strokeWidth={1.5} dot={false} unit="°C" />
                    </ComposedChart>
                  )}
                </ResponsiveContainer>
              </div>
            )}

            {/* Humidity Chart */}
            {(tab === "humidity" || tab === "both") && (
              <div style={{
                background: "rgba(255,255,255,0.03)", border: "1px solid #102d4a",
                borderRadius: 16, padding: "24px 12px 12px", marginBottom: 20
              }}>
                <div style={{ paddingLeft: 16, marginBottom: 16 }}>
                  <div style={{ fontSize: 13, color: "#38bdf8", letterSpacing: 2, textTransform: "uppercase" }}>Relative Humidity</div>
                  <div style={{ fontSize: 18, fontWeight: 700, color: "#e0f4ff", marginTop: 4 }}>
                    {view === "monthly" ? "Monthly Averages" : `Daily Records — ${yearFilter === "all" ? "All Years" : yearFilter}`}
                  </div>
                </div>
                <ResponsiveContainer width="100%" height={260}>
                  {view === "monthly" ? (
                    <BarChart data={chartData} margin={{ top: 5, right: 20, left: 0, bottom: 5 }}>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3" />
                      <XAxis dataKey="label" tick={{ fill: "#4a8aaa", fontSize: 11 }} interval={2} />
                      <YAxis tick={{ fill: "#4a8aaa", fontSize: 11 }} unit="%" domain={[40, 100]} />
                      <Tooltip content={<CustomTooltip />} />
                      <ReferenceLine y={80} stroke="#7dd3fc" strokeDasharray="4 2" label={{ value: "Monsoon peak ~80%", fill: "#7dd3fc", fontSize: 10, position: "insideTopLeft" }} />
                      <Bar dataKey="humidity" name="Avg Humidity" fill="#0ea5e9" radius={[4, 4, 0, 0]} unit="%" />
                    </BarChart>
                  ) : (
                    <AreaChart data={chartData} margin={{ top: 5, right: 20, left: 0, bottom: 5 }}>
                      <defs>
                        <linearGradient id="humGrad" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#0ea5e9" stopOpacity={0.4}/>
                          <stop offset="95%" stopColor="#0ea5e9" stopOpacity={0.05}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3" />
                      <XAxis dataKey="label" tick={{ fill: "#4a8aaa", fontSize: 10 }} interval={Math.floor(daily.length / 12)} />
                      <YAxis tick={{ fill: "#4a8aaa", fontSize: 11 }} unit="%" domain={[30, 100]} />
                      <Tooltip content={<CustomTooltip />} />
                      <ReferenceLine y={80} stroke="#7dd3fc" strokeDasharray="4 2" />
                      <Area type="monotone" dataKey="humidity" name="Humidity" stroke="#0ea5e9" fill="url(#humGrad)" strokeWidth={1.5} dot={false} unit="%" />
                    </AreaChart>
                  )}
                </ResponsiveContainer>
              </div>
            )}

            {/* Seasonal Summary */}
            <div style={{
              background: "rgba(255,255,255,0.03)", border: "1px solid #102d4a",
              borderRadius: 16, padding: "24px", marginTop: 4
            }}>
              <div style={{ fontSize: 13, color: "#38bdf8", letterSpacing: 2, textTransform: "uppercase", marginBottom: 16 }}>Seasonal Patterns — Khulna</div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 14 }}>
                {[
                  { season: "☁️ Monsoon", months: "Jun – Sep", temp: "29–33°C", hum: "80–90%", note: "Peak humidity & rainfall" },
                  { season: "🌸 Pre-monsoon", months: "Mar – May", temp: "33–36°C", hum: "60–75%", note: "Hottest period of year" },
                  { season: "🍂 Post-monsoon", months: "Oct – Nov", temp: "28–32°C", hum: "70–80%", note: "Cooling with late rains" },
                  { season: "❄️ Winter", months: "Dec – Feb", temp: "15–27°C", hum: "55–70%", note: "Driest & coolest season" },
                ].map((s, i) => (
                  <div key={i} style={{
                    background: "rgba(14,165,233,0.06)", border: "1px solid #0c3a5e",
                    borderRadius: 12, padding: "16px 18px"
                  }}>
                    <div style={{ fontSize: 15, fontWeight: 700, color: "#7dd3fc", marginBottom: 6 }}>{s.season}</div>
                    <div style={{ fontSize: 12, color: "#4a8aaa", marginBottom: 8 }}>{s.months}</div>
                    <div style={{ fontSize: 13, color: "#e0f4ff", marginBottom: 2 }}>🌡️ {s.temp}</div>
                    <div style={{ fontSize: 13, color: "#e0f4ff", marginBottom: 8 }}>💧 {s.hum}</div>
                    <div style={{ fontSize: 11, color: "#64a7c8", fontStyle: "italic" }}>{s.note}</div>
                  </div>
                ))}
              </div>
            </div>

            <div style={{ textAlign: "center", marginTop: 20, fontSize: 11, color: "#2a5a7a" }}>
              Data source: Open-Meteo Historical Weather Archive · ERA5 Reanalysis · 2021–2024
            </div>
          </>
        )}
      </div>
    </div>
  );
  //return default KhulnaWeather;
}
